class NotificationSoundGenerator{constructor(){this.audioContext=null;this.initAudioContext()}initAudioContext(){try{const AudioContext=window.AudioContext||window.webkitAudioContext;this.audioContext=new AudioContext()}catch(e){console.warn('Web Audio API not supported')}}playNotificationBeep(){if(!this.audioContext)return;if(this.audioContext.state==='suspended'){this.audioContext.resume()}const now=this.audioContext.currentTime;const oscillator=this.audioContext.createOscillator();const gainNode=this.audioContext.createGain();oscillator.connect(gainNode);gainNode.connect(this.audioContext.destination);oscillator.frequency.setValueAtTime(1046.5,now);oscillator.frequency.setValueAtTime(1318.5,now+0.1);oscillator.type='sine';gainNode.gain.setValueAtTime(0,now);gainNode.gain.linearRampToValueAtTime(0.3,now+0.05);gainNode.gain.linearRampToValueAtTime(0.3,now+0.15);gainNode.gain.linearRampToValueAtTime(0,now+0.3);oscillator.start(now);oscillator.stop(now+0.3)}playCriticalAlert(){if(!this.audioContext)return;if(this.audioContext.state==='suspended'){this.audioContext.resume()}const now=this.audioContext.currentTime;for(let i=0;i<3;i++){const startTime=now+(i*0.4);const oscillator=this.audioContext.createOscillator();const gainNode=this.audioContext.createGain();oscillator.connect(gainNode);gainNode.connect(this.audioContext.destination);oscillator.frequency.setValueAtTime(1568,startTime);oscillator.type='sine';gainNode.gain.setValueAtTime(0,startTime);gainNode.gain.linearRampToValueAtTime(0.4,startTime+0.05);gainNode.gain.linearRampToValueAtTime(0,startTime+0.15);oscillator.start(startTime);oscillator.stop(startTime+0.15)}}playSuccessSound(){if(!this.audioContext)return;if(this.audioContext.state==='suspended'){this.audioContext.resume()}const now=this.audioContext.currentTime;const oscillator=this.audioContext.createOscillator();const gainNode=this.audioContext.createGain();oscillator.connect(gainNode);gainNode.connect(this.audioContext.destination);oscillator.frequency.setValueAtTime(523,now);oscillator.frequency.setValueAtTime(659,now+0.08);oscillator.frequency.setValueAtTime(784,now+0.16);oscillator.type='sine';gainNode.gain.setValueAtTime(0,now);gainNode.gain.linearRampToValueAtTime(0.25,now+0.05);gainNode.gain.linearRampToValueAtTime(0.25,now+0.2);gainNode.gain.linearRampToValueAtTime(0,now+0.35);oscillator.start(now);oscillator.stop(now+0.35)}}window.NotificationSound=new NotificationSoundGenerator();